import os
from typing import List

import modal

APP_NAME = "modal-gpu-batch-inference"
VOLUME_NAME = "modal-gpu-batch-inference-vol"
SECRET_NAME = "modal-gpu-batch-inference-secret"
WEIGHTS_PATH = "/models/weights.npy"

image = modal.Image.debian_slim().pip_install("numpy")
app = modal.App(APP_NAME)
volume = modal.Volume.from_name(VOLUME_NAME, create_if_missing=True)
secret = modal.Secret.from_name(SECRET_NAME)

modal_gpu_batch_inference_output: dict = {}


def _store_output(payload: dict) -> None:
    modal_gpu_batch_inference_output.update(payload)
    globals()["modal-gpu-batch-inference-output"] = modal_gpu_batch_inference_output


@app.cls(
    gpu="T4",
    image=image,
    volumes={"/models": volume},
    secrets=[secret],
)
class BatchInferenceModel:
    @modal.enter()
    def load_weights(self) -> None:
        import numpy as np

        if os.path.exists(WEIGHTS_PATH):
            self.weights = np.load(WEIGHTS_PATH)
        else:
            self.weights = np.random.randn(128, 128).astype(np.float32)
            os.makedirs(os.path.dirname(WEIGHTS_PATH), exist_ok=True)
            np.save(WEIGHTS_PATH, self.weights)
            volume.commit()

    @modal.method()
    def infer(self, batch: List[List[float]]) -> List[float]:
        import numpy as np

        inputs = np.asarray(batch, dtype=np.float32)
        predictions = inputs @ self.weights
        return predictions.mean(axis=1).tolist()


@app.local_entrypoint()
def main() -> None:
    import numpy as np

    model_name = os.environ.get("MODEL_NAME", "modal-batch-model")
    batch_size = int(os.environ.get("INFERENCE_BATCH_SIZE", "16"))

    batches = [
        np.random.randn(batch_size, 128).astype(np.float32).tolist()
        for _ in range(8)
    ]

    model = BatchInferenceModel()
    batch_outputs = list(model.infer.map(batches))

    flattened = [value for batch in batch_outputs for value in batch]
    avg_prediction = float(np.mean(flattened)) if flattened else 0.0

    output_payload = {
        "model_name": model_name,
        "total_samples": len(flattened),
        "batches_processed": len(batch_outputs),
        "avg_prediction": avg_prediction,
        "weights_path": WEIGHTS_PATH,
    }
    _store_output(output_payload)

    print(output_payload)
